 1	import React, { FC } from 'react';
 2	import { Controller, useFormContext } from 'react-hook-form';
 3	
 4	import { IoK8sApiCoreV1Service } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
 5	import {
 6	  DropdownItem,
 7	  FormGroup,
 8	  FormHelperText,
 9	  HelperText,
10	  HelperTextItem,
11	} from '@patternfly/react-core';
12	import Select from '@utils/components/Select/Select';
13	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
14	
15	type TargetPortProps = {
16	  service: IoK8sApiCoreV1Service;
17	};
18	
19	const TargetPort: FC<TargetPortProps> = ({ service }) => {
20	  const { t } = useNetworkingTranslation();
21	
22	  const { control, watch } = useFormContext();
23	  const selectedTargetPort = watch('spec.port.targetPort');
24	
25	  const ports = service?.spec?.ports;
26	
27	  const selectedServicePort = ports?.find(
28	    (port) => port.name === selectedTargetPort || port.targetPort === selectedTargetPort,
29	  );
30	
31	  if (!service) return null;
32	
33	  return (
34	    <Controller
35	      control={control}
36	      name="spec.port.targetPort"
37	      render={({ field: { onChange, value } }) => (
38	        <FormGroup fieldId="target-port" isRequired label={t('Target port')}>
39	          <Select
40	            id="target-port"
41	            selected={value}
42	            toggleContent={
43	              selectedServicePort === undefined ? (
44	                t('Select target port')
45	              ) : (
46	                <>
47	                  {selectedServicePort.port} &rarr; {selectedServicePort.targetPort} (
48	                  {selectedServicePort.protocol})
49	                </>
50	              )
51	            }
52	          >
53	            <>
54	              {(ports || []).map((port) => (
55	                <DropdownItem
56	                  key={port.name || port.targetPort}
57	                  onClick={() => {
58	                    onChange(port.name || port.targetPort);
59	                  }}
60	                  value={port.name || port.targetPort}
61	                >
62	                  {port.port} &rarr; {port.targetPort} ({port.protocol})
63	                </DropdownItem>
64	              ))}
65	            </>
66	          </Select>
67	
68	          <FormHelperText>
69	            <HelperText>
70	              <HelperTextItem>{t('Target port for traffic')}</HelperTextItem>
71	            </HelperText>
72	          </FormHelperText>
73	        </FormGroup>
74	      )}
75	      rules={{ required: true }}
76	    />
77	  );
78	};
79	
80	export default TargetPort;

